const token = items[0].json;

if (!token || !token.id) {
  return [{ json: { error: 'Token not found', status: 404 } }];
}

const isExpired = token.expires_at && new Date(token.expires_at) < new Date();

const result = {
  id: token.id,
  code: token.code,
  email: token.email,
  status: isExpired ? 'expired' : token.status,
  is_expired: isExpired,
  price_paid: token.price_paid,
  tier: token.tier,
  coupon_code: token.coupon_code,
  rubric_id: token.rubric_id,
  draft_paper_id: token.draft_paper_id,
  draft_evaluation_id: token.draft_evaluation_id,
  final_paper_id: token.final_paper_id,
  final_evaluation_id: token.final_evaluation_id,
  expires_at: token.expires_at,
  activated_at: token.activated_at,
  created_at: token.created_at,
  rubric: token.programme ? {
    programme: token.programme,
    module_name: token.module_name,
    nqf_level: token.nqf_level,
    assessment_type: token.rubric_assessment_type,
    total_marks: token.total_marks,
    parsed_json: token.parsed_json,
    confirmed: token.confirmed,
    original_filename: token.original_filename
  } : null
};

return [{ json: result }];
